34	/// A structure with functions to declare a [`LivelinessToken`](LivelinessToken),
35	/// query existing [`LivelinessTokens`](LivelinessToken)
36	/// and subscribe to liveliness changes.
37	///
38	/// A [`LivelinessToken`](LivelinessToken) is a token whose liveliness is tied
39	/// to the Zenoh [`Session`](Session) and can be monitored by remote applications.
40	///
41	/// The `Liveliness` structure can be obtained with the
42	/// [`Session::liveliness()`](Session::liveliness) function
43	/// of the [`Session`] struct.
44	///
45	/// # Examples
46	/// ### Declaring a token
47	/// ```
48	/// # #[tokio::main]
49	/// # async fn main() {
50	///
51	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
52	/// let liveliness = session
53	///     .liveliness()
54	///     .declare_token("key/expression")
55	///     .await
56	///     .unwrap();
57	/// # }
58	/// ```
59	///
60	/// ### Querying tokens
61	/// ```
62	/// # #[tokio::main]
63	/// # async fn main() {
64	///
65	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
66	/// let replies = session.liveliness().get("key/**").await.unwrap();
67	/// while let Ok(reply) = replies.recv_async().await {
68	///     if let Ok(sample) = reply.result() {
69	///         println!(">> Liveliness token {}", sample.key_expr());
70	///     }
71	/// }
72	/// # }
73	/// ```
74	///
75	/// ### Subscribing to liveliness changes
76	/// ```no_run
77	/// # #[tokio::main]
78	/// # async fn main() {
79	/// use zenoh::sample::SampleKind;
80	///
81	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
82	/// let subscriber = session.liveliness().declare_subscriber("key/**").await.unwrap();
83	/// while let Ok(sample) = subscriber.recv_async().await {
84	///     match sample.kind() {
85	///         SampleKind::Put => println!("New liveliness: {}", sample.key_expr()),
86	///         SampleKind::Delete => println!("Lost liveliness: {}", sample.key_expr()),
87	///     }
88	/// }
89	/// # }
90	/// ```
91	pub struct Liveliness<'a> {
92	    pub(crate) session: &'a Session,
93	}
