102	    /// Create a [`LivelinessToken`](LivelinessToken) for the given key expression.
103	    ///
104	    /// # Arguments
105	    ///
106	    /// * `key_expr` - The key expression to create the liveliness token on
107	    ///
108	    /// # Examples
109	    /// ```
110	    /// # #[tokio::main]
111	    /// # async fn main() {
112	    ///
113	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
114	    /// let liveliness = session
115	    ///     .liveliness()
116	    ///     .declare_token("key/expression")
117	    ///     .await
118	    ///     .unwrap();
119	    /// # }
120	    /// ```
