122	        &self,
123	        key_expr: TryIntoKeyExpr,
124	    ) -> LivelinessTokenBuilder<'a, 'b>
125	    where
126	        TryIntoKeyExpr: TryInto<KeyExpr<'b>>,
127	        <TryIntoKeyExpr as TryInto<KeyExpr<'b>>>::Error: Into<zenoh_core::Error>,
128	    {
129	        LivelinessTokenBuilder {
130	            session: self.session,
131	            key_expr: TryIntoKeyExpr::try_into(key_expr).map_err(Into::into),
132	        }
133	    }
