135	    /// Create a [`Subscriber`](crate::pubsub::Subscriber) for liveliness changes matching the given key expression.
136	    ///
137	    /// # Arguments
138	    ///
139	    /// * `key_expr` - The key expression to subscribe to
140	    ///
141	    /// # Examples
142	    /// ```no_run
143	    /// # #[tokio::main]
144	    /// # async fn main() {
145	    /// use zenoh::sample::SampleKind;
146	    ///
147	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
148	    /// let subscriber = session.liveliness().declare_subscriber("key/expression").await.unwrap();
149	    /// while let Ok(sample) = subscriber.recv_async().await {
150	    ///     match sample.kind() {
151	    ///         SampleKind::Put => println!("New liveliness: {}", sample.key_expr()),
152	    ///         SampleKind::Delete => println!("Lost liveliness: {}", sample.key_expr()),
153	    ///     }
154	    /// }
155	    /// # }
156	    /// ```
157	    pub fn declare_subscriber<'b, TryIntoKeyExpr>(
158	        &self,
159	        key_expr: TryIntoKeyExpr,
160	    ) -> LivelinessSubscriberBuilder<'a, 'b, DefaultHandler>
161	    where
162	        TryIntoKeyExpr: TryInto<KeyExpr<'b>>,
163	        <TryIntoKeyExpr as TryInto<KeyExpr<'b>>>::Error: Into<zenoh_result::Error>,
164	    {
165	        LivelinessSubscriberBuilder {
166	            session: self.session,
167	            key_expr: TryIntoKeyExpr::try_into(key_expr).map_err(Into::into),
168	            handler: DefaultHandler::default(),
169	            history: false,
170	        }
171	    }
172	
173	    /// Query liveliness tokens with matching key expressions.
174	    ///
175	    /// # Arguments
176	    ///
177	    /// * `key_expr` - The key expression matching liveliness tokens to query
178	    ///
179	    /// # Examples
180	    /// ```
181	    /// # #[tokio::main]
182	    /// # async fn main() {
183	    ///
184	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
185	    /// let replies = session.liveliness().get("key/expression").await.unwrap();
186	    /// while let Ok(reply) = replies.recv_async().await {
187	    ///     if let Ok(sample) = reply.result() {
188	    ///         println!(">> Liveliness token {}", sample.key_expr());
189	    ///     }
190	    /// }
191	    /// # }
192	    /// ```
193	    pub fn get<'b, TryIntoKeyExpr>(
194	        &self,
195	        key_expr: TryIntoKeyExpr,
196	    ) -> LivelinessGetBuilder<'a, 'b, DefaultHandler>
197	    where
198	        TryIntoKeyExpr: TryInto<KeyExpr<'b>>,
199	        <TryIntoKeyExpr as TryInto<KeyExpr<'b>>>::Error: Into<zenoh_result::Error>,
200	    {
201	        let key_expr = key_expr.try_into().map_err(Into::into);
202	        LivelinessGetBuilder {
203	            session: self.session,
204	            key_expr,
205	            timeout: self.session.queries_default_timeout(),
206	            handler: DefaultHandler::default(),
207	            #[cfg(feature = "unstable")]
208	            cancellation_token: None,
209	        }
210	    }
211	}
