226	/// # #[tokio::main]
227	/// # async fn main() {
228	///
229	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
230	/// let liveliness = session
231	///     .liveliness()
232	///     .declare_token("key/expression")
233	///     .await
234	///     .unwrap();
235	/// # }
236	/// ```
237	#[must_use = "Liveliness tokens will be immediately dropped and undeclared if not bound to a variable"]
238	#[derive(Debug)]
239	pub struct LivelinessToken {
240	    pub(crate) session: WeakSession,
241	    pub(crate) id: Id,
