248	/// ```
249	/// # #[tokio::main]
250	/// # async fn main() {
251	///
252	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
253	/// let liveliness = session
254	///     .liveliness()
255	///     .declare_token("key/expression")
256	///     .await
257	///     .unwrap();
258	///
259	/// liveliness.undeclare().await.unwrap();
260	/// # }
261	/// ```
262	#[must_use = "Resolvables do nothing unless you resolve them using `.await` or `zenoh::Wait::wait`"]
263	#[derive(Debug)]
264	pub struct LivelinessTokenUndeclaration(LivelinessToken);
265	
