267	    type To = ZResult<()>;
268	}
269	
270	impl Wait for LivelinessTokenUndeclaration {
271	    fn wait(mut self) -> <Self as Resolvable>::To {
272	        self.0.undeclare_impl()
273	    }
274	}
275	
276	impl IntoFuture for LivelinessTokenUndeclaration {
277	    type Output = <Self as Resolvable>::To;
278	    type IntoFuture = Ready<<Self as Resolvable>::To>;
279	
280	    fn into_future(self) -> Self::IntoFuture {
