286	    /// Undeclare the [`LivelinessToken`].
287	    ///
288	    /// # Examples
289	    /// ```
290	    /// # #[tokio::main]
291	    /// # async fn main() {
292	    ///
293	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
