34	/// # }
35	/// ```
36	#[must_use = "Resolvables do nothing unless you resolve them using `.await` or `zenoh::Wait::wait`"]
37	#[derive(Debug)]
38	pub struct LivelinessTokenBuilder<'a, 'b> {
39	    pub(crate) session: &'a Session,
40	    pub(crate) key_expr: ZResult<KeyExpr<'b>>,
41	}
