48	    #[inline]
49	    fn wait(self) -> <Self as Resolvable>::To {
50	        let session = self.session;
51	        let key_expr = self.key_expr?.into_owned();
52	        session
53	            .declare_liveliness_inner(&key_expr)
54	            .map(|id| LivelinessToken {
55	                session: self.session.downgrade(),
56	                id,
57	                undeclare_on_drop: true,
