91	pub struct LivelinessSubscriberBuilder<'a, 'b, Handler, const BACKGROUND: bool = false> {
92	    pub session: &'a Session,
93	    pub key_expr: ZResult<KeyExpr<'b>>,
94	    pub handler: Handler,
95	    pub history: bool,
96	}
