98	impl<'a, 'b> LivelinessSubscriberBuilder<'a, 'b, DefaultHandler> {
99	    /// Receive the samples for this liveliness subscription with a callback.
100	    ///
101	    /// # Examples
102	    /// ```
103	    /// # #[tokio::main]
104	    /// # async fn main() {
105	    ///
106	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
107	    /// let subscriber = session
108	    ///     .liveliness()
109	    ///     .declare_subscriber("key/expression")
110	    ///     .callback(|sample| { println!("Received: {} {:?}", sample.key_expr(), sample.payload()); })
111	    ///     .await
112	    ///     .unwrap();
113	    /// # }
114	    /// ```
115	    #[inline]
116	    pub fn callback<F>(self, callback: F) -> LivelinessSubscriberBuilder<'a, 'b, Callback<Sample>>
117	    where
118	        F: Fn(Sample) + Send + Sync + 'static,
119	    {
120	        self.with(Callback::from(callback))
121	    }
122	
123	    /// Receive the samples for this liveliness subscription with a mutable callback.
124	    ///
125	    /// Using this guarantees that your callback will never be called concurrently.
126	    /// If your callback is also accepted by the [`callback`](LivelinessSubscriberBuilder::callback) method, we suggest you use it instead of `callback_mut`.
127	    ///
128	    /// # Examples
129	    /// ```
130	    /// # #[tokio::main]
131	    /// # async fn main() {
132	    ///
133	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
134	    /// let mut n = 0;
