144	    pub fn callback_mut<F>(
145	        self,
146	        callback: F,
147	    ) -> LivelinessSubscriberBuilder<'a, 'b, Callback<Sample>>
148	    where
149	        F: FnMut(Sample) + Send + Sync + 'static,
150	    {
151	        self.callback(locked(callback))
152	    }
153	
154	    /// Receive the samples for this liveliness subscription with a [`Handler`](IntoHandler).
155	    ///
156	    /// # Examples
157	    /// ```no_run
158	    /// # #[tokio::main]
159	    /// # async fn main() {
